-- Logbook – Supabase Schema (full snapshot, regenerated from the live DB)
-- Covers migrations 0001–0138. This file is the authoritative current state;
-- it was generated by introspecting the production database (pg_get_functiondef,
-- pg_policies, pg_constraint, information_schema) so policy and function bodies
-- are verbatim. Use it to stand up a fresh project; keep it in sync on schema
-- changes (see CLAUDE.md → "Datenbank").

-- Migration 0132: on a fresh project, `public`'s default privileges (as
-- provisioned by Supabase) grant `anon` direct EXECUTE on every function
-- created afterward, REGARDLESS of a later `REVOKE EXECUTE ... FROM PUBLIC`
-- on that function — that revoke only removes PUBLIC-inherited access, not
-- an explicit direct grant from a default-privileges rule. Discovered when
-- two brand-new SECURITY DEFINER functions (Migration 0131) stayed callable
-- by anon despite the usual REVOKE FROM PUBLIC + GRANT TO authenticated
-- pattern (see the "Grant-Falle" note further down, which only covers the
-- PUBLIC-inheritance path). Closing it here, before any function in this
-- script is created, so a from-scratch rebuild doesn't reintroduce it for
-- every function defined below.
ALTER DEFAULT PRIVILEGES FOR ROLE postgres IN SCHEMA public
  REVOKE EXECUTE ON FUNCTIONS FROM anon;

-- ── Tables ────────────────────────────────────────────────────────────────────

CREATE TABLE public.zane_profiles (
  id   uuid NOT NULL,
  name text NOT NULL,
  approved boolean DEFAULT false  -- overridden below to signup_default_approved() once that fn exists
);

-- Global app config (single row). Drives the zane_profiles.approved default.
-- force_update_nonce (Migration 0131): set by admin_force_update() to push
-- the "New version available" banner to every client without an sw.js bump.
CREATE TABLE public.zane_app_config (
  id int PRIMARY KEY DEFAULT 1,
  signup_requires_approval boolean NOT NULL DEFAULT true,
  auto_approve_remaining int,
  force_update_nonce text,
  CONSTRAINT zane_app_config_singleton CHECK (id = 1)
);

CREATE TABLE public.zane_exercises (
  id text NOT NULL,
  user_id uuid NOT NULL,
  name text NOT NULL,
  tags text[] DEFAULT '{}'::text[],
  note text NOT NULL DEFAULT ''::text,
  category text,
  unilateral boolean NOT NULL DEFAULT false,
  equipment text,
  progression_reps integer,
  movement_type text,
  no_weight_reps boolean NOT NULL DEFAULT false,
  log_mode text,
  pull_bodyweight boolean NOT NULL DEFAULT false,
  youtube_url text
);

CREATE TABLE public.zane_schedules (
  id text NOT NULL,
  user_id uuid NOT NULL,
  name text NOT NULL,
  days jsonb NOT NULL DEFAULT '[]'::jsonb,
  archived boolean NOT NULL DEFAULT false,
  versions jsonb NOT NULL DEFAULT '[]'::jsonb,
  is_flex boolean NOT NULL DEFAULT false,
  sessions_per_week integer,
  mesocycle_weeks integer,
  mesocycle_start_rir integer,
  mesocycle_end_rir integer
);

CREATE TABLE public.zane_sessions (
  id text NOT NULL,
  user_id uuid NOT NULL,
  schedule_id text,
  day_id text,
  day_name text,
  date timestamp with time zone,
  ended timestamp with time zone,
  entries jsonb NOT NULL DEFAULT '[]'::jsonb,
  started_at timestamp with time zone,
  duration_minutes integer,
  feel text,
  is_bonus boolean NOT NULL DEFAULT false,
  is_freestyle boolean NOT NULL DEFAULT false,
  is_deload boolean NOT NULL DEFAULT false
);

CREATE TABLE public.zane_session_entries (
  id text NOT NULL,
  session_id text NOT NULL,
  user_id uuid NOT NULL,
  entry_idx integer NOT NULL,
  ex_id text,
  name text NOT NULL DEFAULT ''::text,
  planned_sets integer,
  planned_reps integer,
  note text NOT NULL DEFAULT ''::text,
  superset_group text,
  planned_reps_per_set integer[],
  planned_reps_max integer,
  planned_progression_offset integer
);

CREATE TABLE public.zane_sets (
  id text NOT NULL,
  session_id text NOT NULL,
  entry_id text NOT NULL,
  user_id uuid NOT NULL,
  set_idx integer NOT NULL,
  kg numeric,
  reps integer,
  reps_l integer,
  reps_r integer,
  done boolean NOT NULL DEFAULT false,
  skipped boolean NOT NULL DEFAULT false,
  warmup boolean NOT NULL DEFAULT false,
  updated_at timestamp with time zone NOT NULL DEFAULT now()
);

CREATE TABLE public.zane_cardio_logs (
  id               text        NOT NULL,
  user_id          uuid        NOT NULL,
  date             text        NOT NULL,
  type             text,
  duration_minutes integer     NOT NULL,
  distance_m       numeric,
  pace_feeling     integer     CHECK (pace_feeling BETWEEN 1 AND 6),
  effort           integer     CHECK (effort BETWEEN 1 AND 10),
  note             text,
  created_at       timestamp with time zone NOT NULL DEFAULT now(),
  session_id       text        -- links a logged cardio session back to its zane_sessions row
);

CREATE TABLE public.zane_daily_logs (
  id           text        NOT NULL,
  user_id      uuid        NOT NULL,
  date         text        NOT NULL,
  weight       numeric,
  steps        integer,
  calories     integer,
  protein      integer,
  carbs        integer,
  fat          integer,
  fiber        integer,
  water_ml     integer,
  note         text,
  adherence          numeric,
  targets_snap       jsonb,
  off_plan_note      text,
  daily_coach_fields jsonb,
  updated_at         timestamp with time zone NOT NULL DEFAULT now(),
  created_at         timestamp with time zone NOT NULL DEFAULT now(),
  CONSTRAINT zane_daily_logs_user_id_date_key UNIQUE (user_id, date)
);

CREATE TABLE public.zane_skips (
  id text NOT NULL,
  user_id uuid,
  date text NOT NULL,
  day_id text,
  day_name text,
  skip_reason text,
  skipped_at timestamp with time zone DEFAULT now()
);

CREATE TABLE public.zane_user_settings (
  user_id uuid NOT NULL,
  active_schedule_id text,
  cycle_index integer NOT NULL DEFAULT 0,
  last_advanced_date date,
  unit text,
  rest_default integer NOT NULL DEFAULT 120,
  in_progress_session_id text,
  cycle_start_date text,
  push_enabled boolean DEFAULT false,
  rest_big integer DEFAULT 180,
  rest_medium integer DEFAULT 120,
  rest_small integer DEFAULT 90,
  cycle_week_view boolean DEFAULT false,
  accent_color text DEFAULT 'gold'::text,
  dark_mode text DEFAULT 'dark'::text,
  pushover_user_key text,
  use_pushover boolean DEFAULT false,
  week_plan_start_date date,
  tempo_enabled boolean DEFAULT false,
  tempo_eccentric numeric DEFAULT 4,
  tempo_concentric numeric DEFAULT 1,
  smart_progression boolean DEFAULT false,
  progression_range_top integer DEFAULT 4,
  equipment_config jsonb,
  custom_day_types text[] NOT NULL DEFAULT '{}'::text[],
  reminder_enabled boolean NOT NULL DEFAULT false,
  reminder_time text NOT NULL DEFAULT '07:00'::text,
  next_reminder_at timestamp with time zone,
  show_warmup_in_summary boolean NOT NULL DEFAULT true,
  show_regression boolean NOT NULL DEFAULT true,
  show_coaching_tab boolean DEFAULT false,
  be_your_own_coach boolean NOT NULL DEFAULT false,
  session_timeout_minutes integer DEFAULT 90,
  auto_close_notify jsonb,
  macro_targets jsonb,
  show_health_tab boolean NOT NULL DEFAULT false,
  weight_fill_down boolean NOT NULL DEFAULT true,
  manual_calories boolean NOT NULL DEFAULT false,
  onboarding_completed boolean DEFAULT false,
  net_carbs boolean NOT NULL DEFAULT false,
  default_checkin_schema jsonb,
  status_mode text,
  status_mode_since timestamp with time zone,
  active_cardio_plan_id text,
  glucose_unit text DEFAULT 'mmol'::text,
  vip_background text,
  deload_prompt_dismissed_at timestamp with time zone,
  sw_version text
);

CREATE TABLE public.zane_pushover_active (
  id    text NOT NULL DEFAULT 'singleton'::text,
  nonce text NOT NULL DEFAULT ''::text
);

CREATE TABLE public.zane_push_subscriptions (
  id         text        NOT NULL,
  user_id    uuid        NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  endpoint   text        NOT NULL,
  p256dh     text        NOT NULL,
  auth       text        NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE public.zane_feature_grants (
  feature text NOT NULL,
  email   text NOT NULL
);

-- ── Coaching ──────────────────────────────────────────────────────────────────

CREATE TABLE public.zane_coaching (
  id text NOT NULL,
  coach_id uuid NOT NULL,
  client_id uuid NOT NULL,
  status text NOT NULL DEFAULT 'pending'::text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  checkin_requested_at timestamp with time zone,
  checkin_enabled boolean NOT NULL DEFAULT true,
  checkin_schema jsonb,          -- coach-defined check-in form schema; null = default schema
  support_status text,           -- support-ticket rows (id LIKE 'support_%'): open|in_progress|resolved
  support_category text,         -- support-ticket rows: feature_request|bug|question
  archived boolean DEFAULT false,
  archived_at timestamp with time zone
);

CREATE TABLE public.zane_coaching_threads (
  id text NOT NULL,
  coaching_id text NOT NULL,
  name text NOT NULL,
  created_by uuid NOT NULL,
  created_at timestamp with time zone NOT NULL DEFAULT now()
);

CREATE TABLE public.zane_coaching_notes (
  id text NOT NULL,
  coaching_id text NOT NULL,
  author_id uuid NOT NULL,
  type text NOT NULL,
  entity_id text,
  entity_name text,
  body text NOT NULL,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  read_at timestamp with time zone,
  thread_id text,
  attachments jsonb
);

CREATE TABLE public.zane_coaching_macros (
  id text NOT NULL,
  coaching_id text NOT NULL,
  set_by uuid NOT NULL,
  set_at timestamp with time zone NOT NULL DEFAULT now(),
  calories_training integer,
  protein_training integer,
  carbs_training integer,
  fat_training integer,
  calories_rest integer,
  protein_rest integer,
  carbs_rest integer,
  fat_rest integer
);

CREATE TABLE public.zane_checkins (
  id text NOT NULL,
  coaching_id text NOT NULL,
  client_id uuid NOT NULL,
  week_start date NOT NULL,
  checked_in_at timestamp with time zone NOT NULL DEFAULT now(),
  weight_today numeric,
  weight_avg_last_week numeric,
  off_plan_notes text,
  hydration_ml integer,
  days_trained integer,
  steps integer,
  cardio_minutes integer,
  cardio_distance_m integer,
  goal_note text,
  hunger integer,
  sleep_quality integer,
  life_stress integer,
  work_stress integer,
  tiredness integer,
  issues_notes text,
  general_note text,
  cardio_pace_feeling integer,
  cardio_effort integer,
  performance_vs_last_week text,
  responses jsonb  -- all field values keyed by field key; primary storage since Migration 0065
);

