-- ── Indexes ───────────────────────────────────────────────────────────────────

CREATE INDEX zane_coaching_client_id_idx ON public.zane_coaching USING btree (client_id);

ALTER TABLE zane_coaching REPLICA IDENTITY FULL;
CREATE INDEX zane_coaching_notes_coaching_id_created_at_idx ON public.zane_coaching_notes USING btree (coaching_id, created_at DESC);
CREATE INDEX zane_coaching_notes_coaching_id_read_at_idx ON public.zane_coaching_notes USING btree (coaching_id, read_at) WHERE (read_at IS NULL);
CREATE INDEX zane_coaching_notes_thread_id_idx ON public.zane_coaching_notes USING btree (thread_id) WHERE (thread_id IS NOT NULL);
CREATE INDEX zane_coaching_threads_coaching_id_created_at_idx ON public.zane_coaching_threads USING btree (coaching_id, created_at);
CREATE INDEX zane_session_entries_session_id_idx ON public.zane_session_entries USING btree (session_id);
CREATE INDEX zane_sets_entry_id_idx ON public.zane_sets USING btree (entry_id);
CREATE INDEX zane_sets_session_id_idx ON public.zane_sets USING btree (session_id);
-- Migration 0126: cover the foreign keys that had no index (advisor 0001).
-- Only the tables defined ABOVE this point are indexed here; the rest
-- (cardio_plans, workout_templates, schedule_backups, meso_states,
-- status_periods) are created further down and get their user_id index in
-- their own section, so this file stays runnable top-to-bottom.
CREATE INDEX IF NOT EXISTS idx_zane_cardio_logs_user_id        ON public.zane_cardio_logs(user_id);
CREATE INDEX IF NOT EXISTS idx_zane_checkins_client_id         ON public.zane_checkins(client_id);
CREATE INDEX IF NOT EXISTS idx_zane_coaching_coach_id          ON public.zane_coaching(coach_id);
CREATE INDEX IF NOT EXISTS idx_zane_coaching_macros_coaching_id ON public.zane_coaching_macros(coaching_id);
CREATE INDEX IF NOT EXISTS idx_zane_coaching_notes_author_id   ON public.zane_coaching_notes(author_id);
CREATE INDEX IF NOT EXISTS idx_zane_coaching_threads_created_by ON public.zane_coaching_threads(created_by);
CREATE INDEX IF NOT EXISTS idx_zane_exercises_user_id          ON public.zane_exercises(user_id);
CREATE INDEX IF NOT EXISTS idx_zane_push_subscriptions_user_id ON public.zane_push_subscriptions(user_id);
CREATE INDEX IF NOT EXISTS idx_zane_schedules_user_id          ON public.zane_schedules(user_id);
CREATE INDEX IF NOT EXISTS idx_zane_session_entries_user_id    ON public.zane_session_entries(user_id);
CREATE INDEX IF NOT EXISTS idx_zane_sessions_user_id           ON public.zane_sessions(user_id);
