-- profiles
CREATE POLICY "own profile" ON public.zane_profiles FOR ALL TO public USING (((select auth.uid()) = id));
CREATE POLICY "coach can read client profile" ON public.zane_profiles FOR SELECT TO public USING (zane_is_coach_of(id));

-- exercises
CREATE POLICY "own exercises" ON public.zane_exercises FOR ALL TO public USING (((select auth.uid()) = user_id));
CREATE POLICY "coach can read client exercises" ON public.zane_exercises FOR SELECT TO public USING (zane_is_coach_of(user_id));
CREATE POLICY "coach can write client exercises" ON public.zane_exercises FOR INSERT TO public WITH CHECK (zane_is_coach_of(user_id));
CREATE POLICY "coach can update client exercises" ON public.zane_exercises FOR UPDATE TO public USING (zane_is_coach_of(user_id));

-- schedules
CREATE POLICY "own schedules" ON public.zane_schedules FOR ALL TO public USING (((select auth.uid()) = user_id));
CREATE POLICY "coach can read client schedules" ON public.zane_schedules FOR SELECT TO public USING (zane_is_coach_of(user_id));
CREATE POLICY "coach can write client schedules" ON public.zane_schedules FOR INSERT TO public WITH CHECK (zane_is_coach_of(user_id));
CREATE POLICY "coach can update client schedules" ON public.zane_schedules FOR UPDATE TO public USING (zane_is_coach_of(user_id));
CREATE POLICY "coach can delete client schedules" ON public.zane_schedules FOR DELETE TO public USING (zane_is_coach_of(user_id));

-- sessions
