CREATE POLICY "coach can write client sessions" ON public.zane_sessions FOR INSERT TO public WITH CHECK (zane_is_coach_of(user_id));
CREATE POLICY "coach can update client sessions" ON public.zane_sessions FOR UPDATE TO public USING (zane_is_coach_of(user_id));

-- session_entries
