-- cardio logs
CREATE POLICY "Users manage own cardio logs" ON public.zane_cardio_logs FOR ALL TO authenticated USING (((select auth.uid()) = user_id)) WITH CHECK (((select auth.uid()) = user_id));
CREATE POLICY "coaches read client cardio logs" ON public.zane_cardio_logs FOR SELECT TO authenticated USING (EXISTS ( SELECT 1 FROM zane_coaching zc WHERE zc.client_id = zane_cardio_logs.user_id AND zc.coach_id = (select auth.uid()) AND zc.coach_id <> zc.client_id AND zc.status = 'active'));

-- daily logs
CREATE POLICY "Users manage own daily logs" ON public.zane_daily_logs FOR ALL TO authenticated USING (((select auth.uid()) = user_id)) WITH CHECK (((select auth.uid()) = user_id));
CREATE POLICY "coach can read client daily logs" ON public.zane_daily_logs FOR SELECT TO authenticated USING (zane_is_coach_of(user_id));

-- push subscriptions
CREATE POLICY "users manage own push subscriptions" ON public.zane_push_subscriptions FOR ALL TO public USING (((select auth.uid()) = user_id)) WITH CHECK (((select auth.uid()) = user_id));

-- skips
CREATE POLICY "own skips" ON public.zane_skips FOR ALL TO public USING ((user_id = (select auth.uid()))) WITH CHECK ((user_id = (select auth.uid())));
CREATE POLICY "coach can read client skips" ON public.zane_skips FOR SELECT TO public USING (zane_is_coach_of(user_id));

-- user_settings
CREATE POLICY "own settings" ON public.zane_user_settings FOR ALL TO public USING (((select auth.uid()) = user_id));
CREATE POLICY "coach can read client settings" ON public.zane_user_settings FOR SELECT TO public USING (zane_is_coach_of(user_id));
CREATE POLICY "coach can update client settings" ON public.zane_user_settings FOR UPDATE TO public USING (zane_is_coach_of(user_id));

-- coaching
CREATE POLICY "coaching visible to participants" ON public.zane_coaching FOR SELECT TO public USING (((coach_id = (select auth.uid())) OR (client_id = (select auth.uid()))));
-- Migration 0125: the UPDATE policies carry WITH CHECK, and the
-- zane_coaching_guard_update trigger (below) makes coach_id/client_id immutable
-- and lets only the client change status.
-- Migration 0137 (audit A2): no direct INSERT policy — invites are created only
-- via the SECURITY DEFINER RPCs (invite_client / enable_self_coaching /
-- open_support_chat / admin_broadcast_message), which enforce the business
-- guards. The direct INSERT privilege is revoked below so a client can't POST
-- arbitrary pending invites (spam).
REVOKE INSERT ON TABLE public.zane_coaching FROM anon, authenticated;
CREATE POLICY "client can respond to invite" ON public.zane_coaching FOR UPDATE TO public USING ((client_id = (select auth.uid()))) WITH CHECK ((client_id = (select auth.uid())));
CREATE POLICY "coach can update coaching row" ON public.zane_coaching FOR UPDATE TO public USING ((coach_id = (select auth.uid()))) WITH CHECK ((coach_id = (select auth.uid())));
CREATE POLICY "participants can end coaching" ON public.zane_coaching FOR DELETE TO public USING (((coach_id = (select auth.uid())) OR (client_id = (select auth.uid()))));

-- coaching_threads
CREATE POLICY "threads visible to participants" ON public.zane_coaching_threads FOR SELECT TO public USING ((EXISTS ( SELECT 1 FROM zane_coaching c WHERE ((c.id = zane_coaching_threads.coaching_id) AND ((c.coach_id = (select auth.uid())) OR (c.client_id = (select auth.uid())))))));
CREATE POLICY "participants can create threads" ON public.zane_coaching_threads FOR INSERT TO public WITH CHECK (((created_by = (select auth.uid())) AND (EXISTS ( SELECT 1 FROM zane_coaching c WHERE ((c.id = zane_coaching_threads.coaching_id) AND (c.status = 'active'::text) AND ((c.coach_id = (select auth.uid())) OR (c.client_id = (select auth.uid()))))))));
CREATE POLICY "participants can delete threads" ON public.zane_coaching_threads FOR DELETE TO public USING ((EXISTS ( SELECT 1 FROM zane_coaching c WHERE ((c.id = zane_coaching_threads.coaching_id) AND ((c.coach_id = (select auth.uid())) OR (c.client_id = (select auth.uid())))))));

-- coaching_notes
CREATE POLICY "notes visible to participants" ON public.zane_coaching_notes FOR SELECT TO public USING ((EXISTS ( SELECT 1 FROM zane_coaching c WHERE ((c.id = zane_coaching_notes.coaching_id) AND ((c.coach_id = (select auth.uid())) OR (c.client_id = (select auth.uid())))))));
CREATE POLICY "participants can write notes" ON public.zane_coaching_notes FOR INSERT TO public WITH CHECK (((author_id = (select auth.uid())) AND (EXISTS ( SELECT 1 FROM zane_coaching c WHERE ((c.id = zane_coaching_notes.coaching_id) AND (c.status = 'active'::text) AND ((c.coach_id = (select auth.uid())) OR (c.client_id = (select auth.uid()))))))));
CREATE POLICY "recipient can mark read" ON public.zane_coaching_notes FOR UPDATE TO public USING (((author_id <> (select auth.uid())) AND (EXISTS ( SELECT 1 FROM zane_coaching c WHERE ((c.id = zane_coaching_notes.coaching_id) AND ((c.coach_id = (select auth.uid())) OR (c.client_id = (select auth.uid()))))))));
CREATE POLICY "participants can delete notes" ON public.zane_coaching_notes FOR DELETE TO public USING ((EXISTS ( SELECT 1 FROM zane_coaching c WHERE ((c.id = zane_coaching_notes.coaching_id) AND ((c.coach_id = (select auth.uid())) OR (c.client_id = (select auth.uid())))))));

-- coaching_macros
CREATE POLICY "Coach can manage macros" ON public.zane_coaching_macros FOR ALL TO public USING ((EXISTS ( SELECT 1 FROM zane_coaching WHERE ((zane_coaching.id = zane_coaching_macros.coaching_id) AND (zane_coaching.coach_id = (select auth.uid()))))));
CREATE POLICY "Client can read macros" ON public.zane_coaching_macros FOR SELECT TO public USING ((EXISTS ( SELECT 1 FROM zane_coaching WHERE ((zane_coaching.id = zane_coaching_macros.coaching_id) AND (zane_coaching.client_id = (select auth.uid()))))));

-- checkins
CREATE POLICY "checkins_client" ON public.zane_checkins FOR ALL TO authenticated
  USING ((client_id = (select auth.uid())))
  WITH CHECK (((client_id = (select auth.uid())) AND (EXISTS ( SELECT 1 FROM zane_coaching c WHERE ((c.id = zane_checkins.coaching_id) AND (c.client_id = (select auth.uid())))))));
CREATE POLICY "checkins_coach_read" ON public.zane_checkins FOR SELECT TO authenticated
  USING ((EXISTS ( SELECT 1 FROM zane_coaching WHERE ((zane_coaching.id = zane_checkins.coaching_id) AND (zane_coaching.coach_id = (select auth.uid())) AND (zane_coaching.status = 'active'::text)))));

-- ── Functions (verbatim from the live database) ────────────────────────────────

CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  INSERT INTO public.zane_user_settings (user_id) VALUES (new.id)
  ON CONFLICT DO NOTHING;
  RETURN new;
END;
$function$;

CREATE OR REPLACE FUNCTION public.zane_is_coach_of(p_client_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select exists (
    select 1 from zane_coaching
    where coach_id = auth.uid()
      and client_id = p_client_id
      and status = 'active'
  )
$function$;

CREATE OR REPLACE FUNCTION public.check_active_users_access()
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() = 'office@btc-prime.biz' THEN
    RETURN true;
  END IF;
  RETURN EXISTS (
    SELECT 1 FROM zane_feature_grants
    WHERE feature = 'active_users' AND email = auth.email()
  );
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_active_users_grants()
 RETURNS TABLE(email text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RETURN;
  END IF;
  RETURN QUERY
  SELECT fg.email FROM zane_feature_grants fg WHERE fg.feature = 'active_users' ORDER BY fg.email;
END;
$function$;

CREATE OR REPLACE FUNCTION public.set_active_users_grant(p_email text, p_granted boolean)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;
  IF p_granted THEN
    INSERT INTO zane_feature_grants (feature, email)
    VALUES ('active_users', lower(trim(p_email)))
    ON CONFLICT DO NOTHING;
  ELSE
    DELETE FROM zane_feature_grants
    WHERE feature = 'active_users' AND email = lower(trim(p_email));
  END IF;
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_pending_users()
 RETURNS TABLE(user_id uuid, name text, email text, created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RETURN;
  END IF;
  RETURN QUERY
    SELECT p.id, p.name, u.email::text, u.created_at
    FROM zane_profiles p
    JOIN auth.users u ON u.id = p.id
    WHERE p.approved = false
    ORDER BY u.created_at ASC;
END;
$function$;

CREATE OR REPLACE FUNCTION public.approve_user(p_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;
  UPDATE zane_profiles SET approved = true WHERE id = p_user_id;
END;
$function$;

CREATE OR REPLACE FUNCTION public.decline_user(p_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM zane_profiles WHERE id = p_user_id AND approved = false) THEN
    RAISE EXCEPTION 'User not found or already approved';
  END IF;
  DELETE FROM zane_profiles WHERE id = p_user_id;
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_recent_signups(p_limit int DEFAULT 50)
 RETURNS TABLE(user_id uuid, name text, email text, created_at timestamptz, approved boolean)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RETURN;
  END IF;
  RETURN QUERY
    SELECT p.id, p.name, u.email::text, u.created_at, p.approved
    FROM zane_profiles p
    JOIN auth.users u ON u.id = p.id
    ORDER BY u.created_at DESC
    LIMIT GREATEST(p_limit, 1);
END;
$function$;

-- All-users admin lookup (name/email/last-known SW version/plan count),
-- covering every account regardless of activity — folds in what the
-- Active Users (only currently/recently training), Recent Sign-ups (only
-- the last 50 registrations) and get_users_with_plans (only onboarded)
-- views each covered a subset of; the "All users" admin sheet filters
-- client-side on plan_count/created_at/sw_version instead of needing
-- separate RPCs per filter.
CREATE OR REPLACE FUNCTION public.get_all_users_admin()
 RETURNS TABLE(user_id uuid, name text, email text, sw_version text, created_at timestamptz, approved boolean, plan_count int)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RETURN;
  END IF;
  RETURN QUERY
    SELECT p.id, p.name, u.email::text, us.sw_version, u.created_at, p.approved,
           COALESCE(sc.plan_count, 0)::int AS plan_count
    FROM zane_profiles p
    JOIN auth.users u ON u.id = p.id
    LEFT JOIN zane_user_settings us ON us.user_id = p.id
    LEFT JOIN (
      -- Table-qualified: unqualified "user_id" is ambiguous against the
      -- function's own user_id OUT parameter and fails at call time.
      SELECT s.user_id, COUNT(*) AS plan_count FROM zane_schedules s GROUP BY s.user_id
    ) sc ON sc.user_id = p.id
    ORDER BY u.created_at DESC;
END;
$function$;

-- Full plan detail (all schedules, days, items with resolved exercise
-- name/movement_type/unilateral) for one user — used by the "All users"
-- admin sheet when tapping a row.
CREATE OR REPLACE FUNCTION public.get_user_detail_admin(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RETURN NULL;
  END IF;
  RETURN (
    SELECT jsonb_build_object(
      'active_schedule_id', (
        SELECT us.active_schedule_id FROM zane_user_settings us WHERE us.user_id = p_user_id
      ),
      'plans', (
        SELECT COALESCE(jsonb_agg(
          jsonb_build_object(
            'id',               s.id,
            'name',             s.name,
            'archived',         s.archived,
            'is_flex',          s.is_flex,
            'sessions_per_week', s.sessions_per_week,
            'day_count',        jsonb_array_length(s.days),
            'days', (
              SELECT COALESCE(jsonb_agg(
                jsonb_build_object(
                  'id',    day->>'id',
                  'name',  day->>'name',
                  'items', (
                    SELECT COALESCE(jsonb_agg(
                      jsonb_build_object(
                        'exId',          item->>'exId',
                        'name',          COALESCE(ex.name, item->>'name', '—'),
                        'sets',          (item->>'sets')::int,
                        'reps',          (item->>'reps')::int,
                        'movement_type', ex.movement_type,
                        'unilateral',    ex.unilateral
                      )
                    ), '[]'::jsonb)
                    FROM jsonb_array_elements(day->'items') AS item
                    LEFT JOIN zane_exercises ex
                           ON ex.id = item->>'exId' AND ex.user_id = p_user_id
                  )
                )
              ), '[]'::jsonb)
              FROM jsonb_array_elements(s.days) AS day
            )
          ) ORDER BY s.archived, s.name
        ), '[]'::jsonb)
        FROM zane_schedules s WHERE s.user_id = p_user_id
      )
    )
  );
END;
$function$;

CREATE OR REPLACE FUNCTION public.signup_default_approved()
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT NOT COALESCE((SELECT signup_requires_approval FROM zane_app_config WHERE id = 1), true);
$function$;

-- Now that the helper exists, point the column default at it.
ALTER TABLE public.zane_profiles ALTER COLUMN approved SET DEFAULT public.signup_default_approved();

CREATE OR REPLACE FUNCTION public.get_signup_requires_approval()
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;
  RETURN COALESCE((SELECT signup_requires_approval FROM zane_app_config WHERE id = 1), true);
END;
$function$;

CREATE OR REPLACE FUNCTION public.set_signup_requires_approval(p_value boolean)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;
  INSERT INTO zane_app_config (id, signup_requires_approval, auto_approve_remaining)
  VALUES (1, p_value, NULL)
  ON CONFLICT (id) DO UPDATE
    SET signup_requires_approval = EXCLUDED.signup_requires_approval,
        auto_approve_remaining = NULL;
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_signup_config()
 RETURNS TABLE(requires_approval boolean, auto_approve_remaining int)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RETURN;
  END IF;
  RETURN QUERY
    SELECT c.signup_requires_approval, c.auto_approve_remaining
    FROM zane_app_config c WHERE c.id = 1;
END;
$function$;

CREATE OR REPLACE FUNCTION public.set_auto_approve_budget(p_count int)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v int := NULLIF(GREATEST(COALESCE(p_count, 0), 0), 0);
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;
  INSERT INTO zane_app_config (id, signup_requires_approval, auto_approve_remaining)
  VALUES (1, v IS NULL, v)
  ON CONFLICT (id) DO UPDATE
    SET signup_requires_approval = (v IS NULL),
        auto_approve_remaining = v;
END;
$function$;

-- AFTER INSERT on zane_profiles: consume one unit of auto-approve budget per new
-- signup and re-lock registration once it's exhausted.
CREATE OR REPLACE FUNCTION public.signup_consume_budget()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  cfg record;
BEGIN
  SELECT signup_requires_approval, auto_approve_remaining INTO cfg
  FROM zane_app_config WHERE id = 1 FOR UPDATE;
  IF cfg.signup_requires_approval = false AND cfg.auto_approve_remaining IS NOT NULL THEN
    IF cfg.auto_approve_remaining <= 1 THEN
      UPDATE zane_app_config SET signup_requires_approval = true, auto_approve_remaining = NULL WHERE id = 1;
    ELSE
      UPDATE zane_app_config SET auto_approve_remaining = auto_approve_remaining - 1 WHERE id = 1;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.find_user_by_email(p_email text)
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select id from auth.users where lower(email) = lower(p_email) limit 1
$function$;

CREATE OR REPLACE FUNCTION public.invite_client(p_email text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_client_id uuid;
  v_id        text;
  v_existing  text;
BEGIN
  v_client_id := find_user_by_email(p_email);
  IF v_client_id IS NULL THEN
    RETURN 'ERROR:not_found';
  END IF;
  IF v_client_id = auth.uid() THEN
    RETURN 'ERROR:self';
  END IF;
  SELECT id INTO v_existing FROM zane_coaching
    WHERE coach_id = auth.uid() AND client_id = v_client_id;
  IF FOUND THEN
    RETURN 'ERROR:exists:' || v_existing;
  END IF;
  PERFORM 1 FROM zane_coaching
    WHERE client_id = v_client_id AND status = 'active';
  IF FOUND THEN
    RETURN 'ERROR:already_coached';
  END IF;
  v_id := 'cch_' || gen_random_uuid()::text;
  INSERT INTO zane_coaching (id, coach_id, client_id, status)
    VALUES (v_id, auth.uid(), v_client_id, 'pending');
  RETURN v_id;
END
$function$;

CREATE OR REPLACE FUNCTION public.respond_to_coaching_invite(p_coaching_id text, p_accept boolean)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  if p_accept then
    delete from zane_coaching
      where client_id = auth.uid()
        and status = 'active'
        and coach_id <> client_id
        and id <> p_coaching_id;
    update zane_coaching
      set status = 'active'
      where id = p_coaching_id and client_id = auth.uid() and status = 'pending';
    delete from zane_coaching
      where client_id = auth.uid()
        and status = 'pending'
        and id <> p_coaching_id;
  else
    delete from zane_coaching
      where id = p_coaching_id and client_id = auth.uid();
  end if;
end
$function$;

CREATE OR REPLACE FUNCTION public.enable_self_coaching()
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_id       text;
  v_existing text;
begin
  select id into v_existing from zane_coaching
    where coach_id = auth.uid() and client_id = auth.uid();
  if found then
    update zane_coaching set status = 'active'
      where id = v_existing and status <> 'active';
    return v_existing;
  end if;
  v_id := 'self_' || gen_random_uuid()::text;
  insert into zane_coaching (id, coach_id, client_id, status)
    values (v_id, auth.uid(), auth.uid(), 'active');
  return v_id;
end
$function$;

CREATE OR REPLACE FUNCTION public.get_coach_info()
 RETURNS TABLE(coaching_id text, coach_id uuid, coach_email text, coach_name text, status text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select c.id, c.coach_id, u.email, coalesce(p.name, u.email), c.status
  from zane_coaching c
  join auth.users u on u.id = c.coach_id
  left join zane_profiles p on p.id = c.coach_id
  where c.client_id = auth.uid()
    and c.coach_id <> c.client_id
$function$;

CREATE OR REPLACE FUNCTION public.get_coaching_clients()
 RETURNS TABLE(coaching_id text, client_id uuid, client_email text, client_name text, status text, checkin_enabled boolean)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT c.id, c.client_id, u.email, COALESCE(p.name, u.email), c.status, c.checkin_enabled
  FROM zane_coaching c
  JOIN auth.users u ON u.id = c.client_id
  LEFT JOIN zane_profiles p ON p.id = c.client_id
  WHERE c.coach_id = auth.uid()
    AND c.coach_id <> c.client_id
$function$;

CREATE OR REPLACE FUNCTION public.get_coach_clients_status()
 RETURNS TABLE(client_id uuid, in_progress_session_id text, status_mode text, status_mode_since timestamptz)
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select us.user_id as client_id, us.in_progress_session_id, us.status_mode, us.status_mode_since
  from zane_user_settings us
  inner join zane_coaching zc on zc.client_id = us.user_id
  where zc.coach_id = auth.uid()
    and zc.coach_id <> zc.client_id
    and zc.status = 'active';
$function$;

CREATE OR REPLACE FUNCTION public.get_coach_checkin_status()
 RETURNS TABLE(coaching_id text, checked_in_at timestamptz)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_week_start date;
begin
  v_week_start := current_date
    - (extract(dow from current_date)::int) * interval '1 day'
    - interval '6 days';

  return query
  select
    c.id as coaching_id,
    (
      select ci.checked_in_at from zane_checkins ci
      where ci.coaching_id = c.id
        and ci.week_start = v_week_start
      limit 1
    ) as checked_in_at
  from zane_coaching c
  where c.coach_id = auth.uid()
    and c.coach_id <> c.client_id
    and c.status = 'active';
end;
$function$;

CREATE OR REPLACE FUNCTION public.sync_sets_batch(p_sets jsonb)
 RETURNS void
 LANGUAGE sql
 SET search_path TO 'public'
AS $function$
  INSERT INTO zane_sets (
    id, session_id, entry_id, user_id,
    set_idx, kg, reps, reps_l, reps_r,
    done, skipped, warmup, technique, drops, updated_at
  )
  SELECT
    s->>'id',
    s->>'session_id',
    s->>'entry_id',
    auth.uid(),
    (s->>'set_idx')::int,
    (s->>'kg')::numeric,
    (s->>'reps')::int,
    (s->>'reps_l')::int,
    (s->>'reps_r')::int,
    COALESCE((s->>'done')::boolean,    false),
    COALESCE((s->>'skipped')::boolean, false),
    COALESCE((s->>'warmup')::boolean,  false),
    NULLIF(s->>'technique', ''),
    CASE WHEN s->'drops' IS NOT NULL AND s->'drops' != 'null'::jsonb THEN s->'drops' ELSE NULL END,
    (s->>'updated_at')::timestamptz
  FROM jsonb_array_elements(p_sets) AS s
  ON CONFLICT (id) DO UPDATE SET
    kg         = EXCLUDED.kg,
    reps       = EXCLUDED.reps,
    reps_l     = EXCLUDED.reps_l,
    reps_r     = EXCLUDED.reps_r,
    done       = EXCLUDED.done,
    skipped    = EXCLUDED.skipped,
    warmup     = EXCLUDED.warmup,
    technique  = EXCLUDED.technique,
    drops      = EXCLUDED.drops,
    updated_at = EXCLUDED.updated_at
  WHERE zane_sets.updated_at < EXCLUDED.updated_at;
$function$;

-- Batch upsert for daily logs. Resolves conflicts on (user_id, date) — keeping
-- the existing row's id — so two devices logging the same day don't collide on
-- the UNIQUE(user_id, date) constraint, and only overwrites when the incoming
-- updated_at is newer (no stale clobber). Migration 0096.
CREATE OR REPLACE FUNCTION public.sync_daily_logs_batch(p_logs jsonb)
 RETURNS void
 LANGUAGE sql
 SET search_path TO 'public'
AS $function$
  INSERT INTO zane_daily_logs (
    id, user_id, date, weight, steps, calories, protein, carbs, fat, fiber,
    water_ml, note, off_plan_note, adherence, targets_snap, daily_coach_fields, updated_at
  )
  SELECT
    l->>'id',
    auth.uid(),
    l->>'date',
    (l->>'weight')::numeric,
    (l->>'steps')::int,
    (l->>'calories')::int,
    (l->>'protein')::int,
    (l->>'carbs')::int,
    (l->>'fat')::int,
    (l->>'fiber')::int,
    (l->>'water_ml')::int,
    l->>'note',
    l->>'off_plan_note',
    (l->>'adherence')::numeric,
    CASE WHEN l->'targets_snap' IS NULL OR l->'targets_snap' = 'null'::jsonb THEN NULL ELSE l->'targets_snap' END,
    CASE WHEN l->'daily_coach_fields' IS NULL OR l->'daily_coach_fields' = 'null'::jsonb THEN NULL ELSE l->'daily_coach_fields' END,
    COALESCE((l->>'updated_at')::timestamptz, now())
  FROM jsonb_array_elements(p_logs) AS l
  ON CONFLICT (user_id, date) DO UPDATE SET
    weight             = EXCLUDED.weight,
    steps              = EXCLUDED.steps,
    calories           = EXCLUDED.calories,
    protein            = EXCLUDED.protein,
    carbs              = EXCLUDED.carbs,
    fat                = EXCLUDED.fat,
    fiber              = EXCLUDED.fiber,
    water_ml           = EXCLUDED.water_ml,
    note               = EXCLUDED.note,
    off_plan_note      = EXCLUDED.off_plan_note,
    adherence          = EXCLUDED.adherence,
    targets_snap       = EXCLUDED.targets_snap,
    daily_coach_fields = EXCLUDED.daily_coach_fields,
    updated_at         = EXCLUDED.updated_at
  WHERE zane_daily_logs.updated_at < EXCLUDED.updated_at;
$function$;

-- Build the store-shaped (camelCase) entries array for a session from the
-- relational tables — the single source of truth since migration 0058. Used by
-- the reporting RPCs below (the legacy zane_sessions.entries JSONB is no longer
-- written by the client).
CREATE OR REPLACE FUNCTION public.zane_entries_json(p_session_id text)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'exId', e.ex_id,
      'name', e.name,
      'plannedSets', e.planned_sets,
      'plannedReps', e.planned_reps,
      'plannedRepsPerSet', e.planned_reps_per_set,
      'plannedRepsMax', e.planned_reps_max,
      'plannedProgressionOffset', e.planned_progression_offset,
      'note', e.note,
      'supersetGroup', e.superset_group,
      'category', ex.category,
      'equipment', ex.equipment,
      'movementType', ex.movement_type,
      'sets', COALESCE((
        SELECT jsonb_agg(
          jsonb_build_object(
            'kg', st.kg, 'reps', st.reps, 'repsL', st.reps_l, 'repsR', st.reps_r,
            'done', st.done, 'skipped', st.skipped, 'warmup', st.warmup,
            'technique', st.technique, 'drops', st.drops
          ) ORDER BY st.set_idx)
        FROM zane_sets st WHERE st.entry_id = e.id
      ), '[]'::jsonb)
    ) ORDER BY e.entry_idx
  ), '[]'::jsonb)
  FROM zane_session_entries e
  LEFT JOIN zane_exercises ex ON ex.id = e.ex_id
  WHERE e.session_id = p_session_id;
$function$;

-- Internal-only (audit A1, Migration 0136): filters only by session_id with no
-- owner/coach check, so no client role may call it directly (would be a
-- cross-tenant read). Reached solely by the definer-owned reporting RPCs below,
-- which run as the owner and enforce access.
REVOKE EXECUTE ON FUNCTION public.zane_entries_json(text) FROM PUBLIC, anon, authenticated;

CREATE OR REPLACE FUNCTION public.get_active_sessions_overview()
 RETURNS TABLE(user_id uuid, session_id text, user_name text, day_name text, sets_done integer, sets_total integer, started_at timestamp with time zone, ended timestamp with time zone, is_finished boolean, avg_duration_seconds double precision, avg_sets_total double precision)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' AND
     NOT EXISTS (SELECT 1 FROM zane_feature_grants WHERE feature = 'active_users' AND email = auth.email())
  THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    us.user_id,
    s.id::text AS session_id,
    p.name::text AS user_name,
    s.day_name::text,
    (SELECT COUNT(*) FROM zane_sets st WHERE st.session_id = s.id AND st.done)::int AS sets_done,
    (SELECT COUNT(*) FROM zane_sets st WHERE st.session_id = s.id AND NOT st.skipped)::int AS sets_total,
    s.started_at,
    NULL::timestamptz AS ended,
    false AS is_finished,
    (
      SELECT AVG(CASE WHEN s2.duration_minutes IS NOT NULL THEN s2.duration_minutes * 60.0
                      ELSE EXTRACT(EPOCH FROM (s2.ended - s2.started_at)) END)
      FROM zane_sessions s2
      WHERE s2.user_id = us.user_id AND s2.day_id = s.day_id AND s2.ended IS NOT NULL
        AND (s2.duration_minutes IS NOT NULL OR (s2.started_at IS NOT NULL AND s2.ended > s2.started_at))
    )::float AS avg_duration_seconds,
    (
      SELECT AVG(sub.cnt)::float FROM (
        SELECT (SELECT COUNT(*) FROM zane_sets st WHERE st.session_id = s2.id AND st.done) AS cnt
        FROM zane_sessions s2
        WHERE s2.user_id = us.user_id AND s2.day_id = s.day_id AND s2.ended IS NOT NULL
          AND (s2.duration_minutes IS NOT NULL OR (s2.started_at IS NOT NULL AND s2.ended > s2.started_at))
      ) sub
    )::float AS avg_sets_total
  FROM zane_user_settings us
  JOIN zane_sessions s ON s.id = us.in_progress_session_id
  LEFT JOIN zane_profiles p ON p.id = us.user_id
  WHERE us.in_progress_session_id IS NOT NULL AND s.ended IS NULL

  UNION ALL

  SELECT
    fs.user_id,
    fs.id::text AS session_id,
    p.name::text AS user_name,
    fs.day_name::text,
    (SELECT COUNT(*) FROM zane_sets st WHERE st.session_id = fs.id AND st.done)::int AS sets_done,
    (SELECT COUNT(*) FROM zane_sets st WHERE st.session_id = fs.id AND NOT st.skipped)::int AS sets_total,
    fs.started_at,
    fs.ended,
    true AS is_finished,
    (
      SELECT AVG(CASE WHEN s2.duration_minutes IS NOT NULL THEN s2.duration_minutes * 60.0
                      ELSE EXTRACT(EPOCH FROM (s2.ended - s2.started_at)) END)
      FROM zane_sessions s2
      WHERE s2.user_id = fs.user_id AND s2.day_id = fs.day_id AND s2.ended IS NOT NULL
        AND (s2.duration_minutes IS NOT NULL OR (s2.started_at IS NOT NULL AND s2.ended > s2.started_at))
    )::float AS avg_duration_seconds,
    (
      SELECT AVG(sub.cnt)::float FROM (
        SELECT (SELECT COUNT(*) FROM zane_sets st WHERE st.session_id = s2.id AND st.done) AS cnt
        FROM zane_sessions s2
        WHERE s2.user_id = fs.user_id AND s2.day_id = fs.day_id AND s2.ended IS NOT NULL
          AND (s2.duration_minutes IS NOT NULL OR (s2.started_at IS NOT NULL AND s2.ended > s2.started_at))
      ) sub
    )::float AS avg_sets_total
  FROM (
    SELECT DISTINCT ON (s.user_id) s.*
    FROM zane_sessions s
    WHERE s.ended IS NOT NULL
      AND s.ended > NOW() - INTERVAL '24 hours'
      AND (s.duration_minutes IS NOT NULL OR (s.started_at IS NOT NULL AND s.ended > s.started_at))
    ORDER BY s.user_id, s.ended DESC
  ) fs
  LEFT JOIN zane_profiles p ON p.id = fs.user_id
  WHERE NOT EXISTS (
    SELECT 1 FROM zane_user_settings us2
    JOIN zane_sessions s2 ON s2.id = us2.in_progress_session_id
    WHERE us2.user_id = fs.user_id AND s2.ended IS NULL
  );
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_active_session_detail(p_user_id uuid, p_session_id text DEFAULT NULL::text)
 RETURNS TABLE(user_name text, day_name text, started_at timestamp with time zone, ended timestamp with time zone, entries jsonb, avg_duration_seconds double precision, avg_sets_total double precision, last_session_entries jsonb, last_session_duration_seconds double precision, unit text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' AND
     NOT EXISTS (SELECT 1 FROM zane_feature_grants WHERE feature = 'active_users' AND email = auth.email()) AND
     NOT zane_is_coach_of(p_user_id)
  THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    p.name::text AS user_name,
    s.day_name::text,
    s.started_at,
    s.ended,
    zane_entries_json(s.id) AS entries,
    (
      SELECT AVG(CASE WHEN s2.duration_minutes IS NOT NULL THEN s2.duration_minutes * 60.0
                      ELSE EXTRACT(EPOCH FROM (s2.ended - s2.started_at)) END)
      FROM zane_sessions s2
      WHERE s2.user_id = p_user_id AND s2.day_id = s.day_id AND s2.ended IS NOT NULL AND s2.id != s.id
        AND (s2.duration_minutes IS NOT NULL OR (s2.started_at IS NOT NULL AND s2.ended > s2.started_at))
    )::float AS avg_duration_seconds,
    (
      SELECT AVG(sub.cnt)::float FROM (
        SELECT (SELECT COUNT(*) FROM zane_sets st WHERE st.session_id = s2.id AND st.done) AS cnt
        FROM zane_sessions s2
        WHERE s2.user_id = p_user_id AND s2.day_id = s.day_id AND s2.ended IS NOT NULL AND s2.id != s.id
          AND (s2.duration_minutes IS NOT NULL OR (s2.started_at IS NOT NULL AND s2.ended > s2.started_at))
      ) sub
    )::float AS avg_sets_total,
    zane_entries_json((
      SELECT s2.id FROM zane_sessions s2
      WHERE s2.user_id = p_user_id AND s2.day_id = s.day_id AND s2.ended IS NOT NULL AND s2.id != s.id
        AND (s2.duration_minutes IS NOT NULL OR (s2.started_at IS NOT NULL AND s2.ended > s2.started_at))
      ORDER BY s2.ended DESC LIMIT 1
    )) AS last_session_entries,
    (
      SELECT COALESCE(s2.duration_minutes * 60.0, EXTRACT(EPOCH FROM (s2.ended - s2.started_at)))
      FROM zane_sessions s2
      WHERE s2.user_id = p_user_id AND s2.day_id = s.day_id AND s2.ended IS NOT NULL AND s2.id != s.id
        AND (s2.duration_minutes IS NOT NULL OR (s2.started_at IS NOT NULL AND s2.ended > s2.started_at))
      ORDER BY s2.ended DESC LIMIT 1
    )::float AS last_session_duration_seconds,
    COALESCE((SELECT us.unit FROM zane_user_settings us WHERE us.user_id = p_user_id), 'kg')::text AS unit
  FROM zane_sessions s
  LEFT JOIN zane_profiles p ON p.id = s.user_id
  WHERE s.user_id = p_user_id
    AND (
      (p_session_id IS NOT NULL AND s.id = p_session_id)
      OR
      (p_session_id IS NULL AND s.ended IS NULL AND s.id = (
        SELECT us.in_progress_session_id FROM zane_user_settings us WHERE us.user_id = p_user_id
      ))
    );
END;
$function$;

-- ── Server-side history aggregation RPCs (migration 0059) ───────────────

CREATE OR REPLACE FUNCTION public.get_exercise_best_e1rm(p_user_id uuid DEFAULT NULL)
 RETURNS TABLE(ex_id text, best_e1rm double precision)
 LANGUAGE sql STABLE SECURITY INVOKER SET search_path TO 'public'
AS $function$
  WITH uid AS (SELECT COALESCE(p_user_id, auth.uid()) AS id)
  SELECT e.ex_id,
    MAX(st.kg * (1 + (
      CASE WHEN st.reps_l IS NOT NULL OR st.reps_r IS NOT NULL
           THEN LEAST(COALESCE(st.reps_l, st.reps_r), COALESCE(st.reps_r, st.reps_l))
           ELSE st.reps END
    )::numeric / 30.0))::float AS best_e1rm
  FROM zane_session_entries e
  JOIN zane_sets st ON st.entry_id = e.id
  JOIN zane_sessions s ON s.id = e.session_id
  WHERE e.user_id = (SELECT id FROM uid)
    AND e.ex_id IS NOT NULL
    AND s.ended IS NOT NULL
    AND NOT st.warmup AND NOT st.skipped AND st.kg IS NOT NULL
    AND COALESCE(
      CASE WHEN st.reps_l IS NOT NULL OR st.reps_r IS NOT NULL
           THEN LEAST(COALESCE(st.reps_l, st.reps_r), COALESCE(st.reps_r, st.reps_l))
           ELSE st.reps END, 0) > 0
  GROUP BY e.ex_id;
$function$;

-- Recent ended sessions that logged a given exercise, newest first, each with
-- that exercise's sets. Powers seed/progression at session start, the "last
-- time" card and the exercise-history screen without the full history client-side.
CREATE OR REPLACE FUNCTION public.get_exercise_history(p_ex_id text, p_day_id text DEFAULT NULL, p_limit int DEFAULT 12, p_user_id uuid DEFAULT NULL)
 RETURNS TABLE(session_id text, day_id text, date timestamptz, ended timestamptz, sets jsonb)
 LANGUAGE sql STABLE SECURITY INVOKER SET search_path TO 'public'
AS $function$
  WITH uid AS (SELECT COALESCE(p_user_id, auth.uid()) AS id)
  SELECT s.id AS session_id, s.day_id, s.date, s.ended,
    COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'kg', st.kg, 'reps', st.reps, 'repsL', st.reps_l, 'repsR', st.reps_r,
        'done', st.done, 'skipped', st.skipped, 'warmup', st.warmup
      ) ORDER BY st.set_idx)
      FROM zane_sets st WHERE st.entry_id = e.id
    ), '[]'::jsonb) AS sets
  FROM zane_sessions s
  JOIN zane_session_entries e ON e.session_id = s.id
  WHERE e.user_id = (SELECT id FROM uid)
    AND e.ex_id = p_ex_id
    AND s.ended IS NOT NULL
    AND (p_day_id IS NULL OR s.day_id = p_day_id)
    AND EXISTS (SELECT 1 FROM zane_sets st2 WHERE st2.entry_id = e.id
                AND (st2.kg IS NOT NULL OR st2.reps IS NOT NULL OR st2.reps_l IS NOT NULL OR st2.reps_r IS NOT NULL))
  ORDER BY s.ended DESC
  LIMIT GREATEST(p_limit, 1);
$function$;

-- All-time totals for the stats screen (volume = sum kg*effReps over completed
-- working sets; minutes; session + done-set counts). Streaks stay client-side
-- (plan-aware, need only session dates which boot still loads as metadata).
CREATE OR REPLACE FUNCTION public.get_user_volume_stats(p_user_id uuid DEFAULT NULL)
 RETURNS TABLE(session_count bigint, total_volume double precision, total_minutes bigint, total_done_sets bigint)
 LANGUAGE sql STABLE SECURITY INVOKER SET search_path TO 'public'
AS $function$
  WITH uid AS (SELECT COALESCE(p_user_id, auth.uid()) AS id),
  ended AS (
    SELECT s.id, s.duration_minutes, s.started_at, s.ended
    FROM zane_sessions s WHERE s.user_id = (SELECT id FROM uid) AND s.ended IS NOT NULL
  )
  SELECT
    (SELECT COUNT(*) FROM ended)::bigint AS session_count,
    COALESCE((
      SELECT SUM(st.kg * (
        CASE WHEN st.reps_l IS NOT NULL OR st.reps_r IS NOT NULL
             THEN LEAST(COALESCE(st.reps_l, st.reps_r), COALESCE(st.reps_r, st.reps_l))
             ELSE st.reps END))
      FROM zane_sets st JOIN ended en ON en.id = st.session_id
      WHERE NOT st.warmup AND NOT st.skipped AND st.kg IS NOT NULL
        AND COALESCE(CASE WHEN st.reps_l IS NOT NULL OR st.reps_r IS NOT NULL
             THEN LEAST(COALESCE(st.reps_l, st.reps_r), COALESCE(st.reps_r, st.reps_l))
             ELSE st.reps END, 0) > 0
    ), 0)::float AS total_volume,
    COALESCE((SELECT SUM(COALESCE(en.duration_minutes,
        CASE WHEN en.started_at IS NOT NULL AND en.ended > en.started_at
             THEN EXTRACT(EPOCH FROM (en.ended - en.started_at))/60 ELSE 0 END))::bigint FROM ended en), 0)::bigint AS total_minutes,
    COALESCE((SELECT COUNT(*) FROM zane_sets st JOIN ended en ON en.id = st.session_id
              WHERE st.done AND NOT st.warmup AND NOT st.skipped), 0)::bigint AS total_done_sets;
$function$;

-- Per-session aggregates for the windowed boot (migration 0060): the history
-- list / "best session" card / coach session lists need volume + set/exercise
-- counts for sessions whose sets weren't loaded. Semantics match the client's
-- totalVolume()/doneSetCount() for ended sessions (done flag not required).
CREATE OR REPLACE FUNCTION public.get_session_stats(p_user_id uuid DEFAULT NULL)
 RETURNS TABLE(session_id text, exercise_count integer, done_sets integer, volume double precision)
 LANGUAGE sql STABLE SECURITY INVOKER SET search_path TO 'public'
AS $function$
  WITH uid AS (SELECT COALESCE(p_user_id, auth.uid()) AS id)
  SELECT s.id AS session_id,
    (SELECT COUNT(*) FROM zane_session_entries e WHERE e.session_id = s.id)::int AS exercise_count,
    (SELECT COUNT(*) FROM zane_sets st WHERE st.session_id = s.id
       AND NOT st.warmup AND NOT st.skipped
       AND st.kg IS NOT NULL
       AND (st.reps IS NOT NULL OR st.reps_l IS NOT NULL OR st.reps_r IS NOT NULL))::int AS done_sets,
    COALESCE((SELECT SUM(st.kg * COALESCE(
        CASE WHEN st.reps_l IS NOT NULL OR st.reps_r IS NOT NULL
             THEN LEAST(COALESCE(st.reps_l, st.reps_r), COALESCE(st.reps_r, st.reps_l))
             ELSE st.reps END, 0))
      FROM zane_sets st WHERE st.session_id = s.id
        AND NOT st.warmup AND NOT st.skipped
        AND st.kg IS NOT NULL
        AND (st.reps IS NOT NULL OR st.reps_l IS NOT NULL OR st.reps_r IS NOT NULL)
    ), 0)::float AS volume
  FROM zane_sessions s
  WHERE s.user_id = (SELECT id FROM uid)
    AND s.ended IS NOT NULL;
$function$;

-- ── Trigger: create user_settings row on signup ────────────────────────────────

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION handle_new_user();

-- ── Trigger: consume auto-approve budget on each new profile ────────────────────

DROP TRIGGER IF EXISTS zane_profiles_consume_budget ON public.zane_profiles;
CREATE TRIGGER zane_profiles_consume_budget
  AFTER INSERT ON public.zane_profiles
  FOR EACH ROW EXECUTE FUNCTION signup_consume_budget();

-- ── Trigger: coaching row immutability guard (Migration 0125) ───────────────────
-- coach_id/client_id can never change; only the client may change status (the
-- pending→active acceptance). Prevents a coach self-activating a pending invite
-- even if an UPDATE policy is loosened.
CREATE OR REPLACE FUNCTION public.zane_coaching_guard_update()
  RETURNS trigger
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path = public, pg_temp
AS $function$
begin
  if new.coach_id <> old.coach_id or new.client_id <> old.client_id then
    raise exception 'coach_id/client_id are immutable';
  end if;
  if new.status is distinct from old.status and (select auth.uid()) <> old.client_id then
    raise exception 'only the client may change coaching status';
  end if;
  return new;
end;
$function$;

DROP TRIGGER IF EXISTS zane_coaching_guard_update ON public.zane_coaching;
CREATE TRIGGER zane_coaching_guard_update
  BEFORE UPDATE ON public.zane_coaching
  FOR EACH ROW EXECUTE FUNCTION zane_coaching_guard_update();

-- Migration 0125 grant changes:
--   REVOKE EXECUTE ON FUNCTION public.find_user_by_email(text) FROM anon, authenticated;
--   REVOKE EXECUTE ON ALL FUNCTIONS IN SCHEMA public FROM anon;
-- and DROP POLICY "chat_attach_select" ON storage.objects (public bucket is
-- served via CDN URL and does not need a listable SELECT policy).
--
-- CORRECTION (Migration 0128): the "REVOKE ... FROM anon" line above did
-- NOT work — every SECURITY DEFINER function is also granted EXECUTE to the
-- PUBLIC pseudo-role by default on creation, and anon inherits through
-- PUBLIC regardless of a role-specific revoke. 0128 revokes from PUBLIC
-- instead (which anon has no way to route around) and re-grants to
-- authenticated for every function client code calls, except
-- find_user_by_email (stays unreachable by any client role — only invoked
-- internally from invite_client). Any NEW SECURITY DEFINER function must
-- explicitly `REVOKE EXECUTE ... FROM PUBLIC` + `GRANT ... TO authenticated`
-- (see admin_broadcast_message below) — the default PUBLIC grant otherwise
-- silently reopens it to anon.

CREATE OR REPLACE FUNCTION public.admin_broadcast_message(p_body text)
RETURNS int
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_admin_id uuid;
  v_count int := 0;
  v_user record;
BEGIN
  SELECT id INTO v_admin_id FROM auth.users WHERE email = 'office@btc-prime.biz' LIMIT 1;
  IF auth.uid() IS NULL OR auth.uid() <> v_admin_id THEN RAISE EXCEPTION 'Unauthorized'; END IF;
  IF p_body IS NULL OR btrim(p_body) = '' THEN RAISE EXCEPTION 'Message body required'; END IF;

  FOR v_user IN
    SELECT id FROM auth.users WHERE id <> v_admin_id
  LOOP
    INSERT INTO zane_coaching (id, coach_id, client_id, status, support_status)
    VALUES ('support_' || v_user.id::text, v_admin_id, v_user.id, 'active', 'open')
    ON CONFLICT (id) DO NOTHING;

    INSERT INTO zane_coaching_notes (id, coaching_id, author_id, type, body)
    VALUES (
      'note_' || replace(gen_random_uuid()::text, '-', ''),
      'support_' || v_user.id::text,
      v_admin_id,
      'general',
      p_body
    );
    v_count := v_count + 1;
  END LOOP;

  RETURN v_count;
END;
$function$;

REVOKE EXECUTE ON FUNCTION public.admin_broadcast_message(text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.admin_broadcast_message(text) TO authenticated;

-- get_force_update_nonce / admin_force_update (Migration 0131): lets the
-- admin push the update banner to every client without an sw.js cache bump.
CREATE OR REPLACE FUNCTION public.get_force_update_nonce()
RETURNS text
LANGUAGE sql
SECURITY DEFINER
SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT force_update_nonce FROM zane_app_config WHERE id = 1;
$function$;

REVOKE EXECUTE ON FUNCTION public.get_force_update_nonce() FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION public.get_force_update_nonce() FROM anon;
GRANT EXECUTE ON FUNCTION public.get_force_update_nonce() TO authenticated;

CREATE OR REPLACE FUNCTION public.admin_force_update()
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_admin_id uuid;
BEGIN
  SELECT id INTO v_admin_id FROM auth.users WHERE email = 'office@btc-prime.biz' LIMIT 1;
  IF auth.uid() IS NULL OR auth.uid() <> v_admin_id THEN RAISE EXCEPTION 'Unauthorized'; END IF;

  INSERT INTO zane_app_config (id, force_update_nonce)
  VALUES (1, gen_random_uuid()::text)
  ON CONFLICT (id) DO UPDATE SET force_update_nonce = EXCLUDED.force_update_nonce;
END;
$function$;

REVOKE EXECUTE ON FUNCTION public.admin_force_update() FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION public.admin_force_update() FROM anon;
GRANT EXECUTE ON FUNCTION public.admin_force_update() TO authenticated;

-- get_support_chats (Migration 0129): excludes a support ticket until the
-- user has sent at least one message of their own — otherwise
-- admin_broadcast_message floods this admin inbox with one entry per user,
-- burying genuine open requests. Reappears the moment the user replies.
CREATE OR REPLACE FUNCTION public.get_support_chats()
RETURNS TABLE (
  coaching_id       text,
  client_id         uuid,
  client_name       text,
  client_email      text,
  support_status    text,
  support_category  text,
  last_message_at   timestamptz,
  last_message_body text,
  unread_count      bigint
)
LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public', 'pg_temp' AS $function$
DECLARE v_admin_id uuid;
BEGIN
  SELECT id INTO v_admin_id FROM auth.users WHERE email = 'office@btc-prime.biz' LIMIT 1;
  IF auth.uid() IS NULL OR auth.uid() <> v_admin_id THEN RAISE EXCEPTION 'Unauthorized'; END IF;
  RETURN QUERY
  SELECT
    c.id,
    c.client_id,
    COALESCE(p.name, u.email)::text,
    u.email::text,
    c.support_status,
    c.support_category,
    (SELECT MAX(n.created_at) FROM zane_coaching_notes n WHERE n.coaching_id = c.id),
    (SELECT n.body          FROM zane_coaching_notes n WHERE n.coaching_id = c.id ORDER BY n.created_at DESC LIMIT 1),
    (SELECT COUNT(*)        FROM zane_coaching_notes n WHERE n.coaching_id = c.id AND n.author_id <> v_admin_id AND n.read_at IS NULL)
  FROM zane_coaching c
  JOIN auth.users u ON u.id = c.client_id
  LEFT JOIN zane_profiles p ON p.id = c.client_id
  WHERE c.id LIKE 'support_%'
    AND NOT COALESCE(c.archived, false)
    AND EXISTS (SELECT 1 FROM zane_coaching_notes n WHERE n.coaching_id = c.id AND n.author_id <> v_admin_id)
  ORDER BY (SELECT MAX(n.created_at) FROM zane_coaching_notes n WHERE n.coaching_id = c.id) DESC NULLS LAST;
END;
$function$;

REVOKE EXECUTE ON FUNCTION public.get_support_chats() FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.get_support_chats() TO authenticated;

