  user_id            uuid        NOT NULL REFERENCES auth.users ON DELETE CASCADE,
  schedule_id        text        NOT NULL,
  weeks              int         NOT NULL,
  start_date         text        NOT NULL,
  start_cycle_index  int         NOT NULL DEFAULT 0,
  started_at         timestamptz,  -- exact block-start anchor for the flex week counter (Migration 0138)
  deltas             jsonb       NOT NULL DEFAULT '{}',
  joint_flags        jsonb       NOT NULL DEFAULT '{}',
  pump_low_counts    jsonb       NOT NULL DEFAULT '{}',
  weight_boosts      jsonb       NOT NULL DEFAULT '{}',
  growth_counts      jsonb       NOT NULL DEFAULT '{}',
  completions        int         NOT NULL DEFAULT 0,
  pending_meso2      boolean     NOT NULL DEFAULT false,
  created_at         timestamptz NOT NULL DEFAULT now(),
  updated_at         timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_zane_meso_states_user_id ON public.zane_meso_states(user_id);

ALTER TABLE zane_meso_states ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users manage own meso states"
  ON zane_meso_states FOR ALL
  USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id);

-- Batch upsert for meso states. Only overwrites when the incoming updated_at
-- is newer (no stale clobber) so two devices training the same mesocycle plan
-- don't silently discard each other's deltas/jointFlags/weightBoosts.
-- Migration 0122. growth_counts added in migration 0130. started_at in 0138
-- (COALESCEd on update so an older client that doesn't send it can't null it).
CREATE OR REPLACE FUNCTION public.sync_meso_states_batch(p_states jsonb)
 RETURNS void
 LANGUAGE sql
 SECURITY INVOKER
 SET search_path TO 'public'
AS $function$
  INSERT INTO zane_meso_states (
    id, user_id, schedule_id, weeks, start_date, start_cycle_index, started_at,
    deltas, joint_flags, pump_low_counts, weight_boosts, growth_counts,
    completions, pending_meso2, updated_at
  )
  SELECT
    m->>'id',
    auth.uid(),
    m->>'schedule_id',
    (m->>'weeks')::int,
    m->>'start_date',
    COALESCE((m->>'start_cycle_index')::int, 0),
    (m->>'started_at')::timestamptz,
    COALESCE(m->'deltas', '{}'::jsonb),
    COALESCE(m->'joint_flags', '{}'::jsonb),
    COALESCE(m->'pump_low_counts', '{}'::jsonb),
    COALESCE(m->'weight_boosts', '{}'::jsonb),
    COALESCE(m->'growth_counts', '{}'::jsonb),
    COALESCE((m->>'completions')::int, 0),
    COALESCE((m->>'pending_meso2')::boolean, false),
    COALESCE((m->>'updated_at')::timestamptz, now())
  FROM jsonb_array_elements(p_states) AS m
  ON CONFLICT (id) DO UPDATE SET
    weeks             = EXCLUDED.weeks,
    start_date        = EXCLUDED.start_date,
    start_cycle_index = EXCLUDED.start_cycle_index,
    started_at        = COALESCE(EXCLUDED.started_at, zane_meso_states.started_at),
    deltas            = EXCLUDED.deltas,
    joint_flags       = EXCLUDED.joint_flags,
    pump_low_counts   = EXCLUDED.pump_low_counts,
    weight_boosts     = EXCLUDED.weight_boosts,
    growth_counts     = EXCLUDED.growth_counts,
    completions       = EXCLUDED.completions,
    pending_meso2     = EXCLUDED.pending_meso2,
    updated_at        = EXCLUDED.updated_at
  WHERE zane_meso_states.updated_at < EXCLUDED.updated_at;
$function$;

-- ── Status periods (migration 0083; deload mode added 0108) ─────────────────────
-- Historical log of sick/vacation/deload periods (ended_at NULL = active). Mirror
-- of zane_user_settings.status_mode/status_mode_since (that's the fast current
-- cache; this table is the full history for the stats "Missed Workouts" cards).

CREATE TABLE zane_status_periods (
  id         text        PRIMARY KEY,
  user_id    uuid        NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  mode       text        NOT NULL CHECK (mode = ANY (ARRAY['sick'::text, 'vacation'::text, 'deload'::text])),
  started_at timestamptz NOT NULL,
  ended_at   timestamptz
);

CREATE INDEX IF NOT EXISTS idx_zane_status_periods_user_id ON public.zane_status_periods(user_id);

ALTER TABLE zane_status_periods ENABLE ROW LEVEL SECURITY;

CREATE POLICY "users manage own status periods"
  ON zane_status_periods FOR ALL TO public
  USING ((user_id = (select auth.uid())));
-- coach read (Migration 0084): needed so computeWeeklyAdherence can exclude a
-- client's sick/vacation days from their training-adherence score.
CREATE POLICY "coaches read client status periods"
  ON zane_status_periods FOR SELECT TO public
  USING (EXISTS ( SELECT 1 FROM zane_coaching zc
    WHERE zc.client_id = zane_status_periods.user_id
      AND zc.coach_id = (select auth.uid()) AND zc.coach_id <> zc.client_id AND zc.status = 'active'));

-- ── Glucose logs (migration 0101) ───────────────────────────────────────────────
-- Multiple readings per day; value always stored in mmol/L (display unit is a
-- per-user setting, zane_user_settings.glucose_unit). Written directly (no diff).

CREATE TABLE zane_glucose_logs (
  id         text        PRIMARY KEY,
  user_id    uuid        NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  date       text        NOT NULL,                 -- YYYY-MM-DD
  time       text        NOT NULL,                 -- HH:MM local
  value_mmol numeric     NOT NULL,
  context    text        NOT NULL DEFAULT 'other'::text,  -- 'fasted'|'fed'|'other'
  note       text,
  created_at timestamptz DEFAULT now()
);

CREATE INDEX zane_glucose_logs_user_date ON public.zane_glucose_logs USING btree (user_id, date DESC, "time" DESC);

ALTER TABLE zane_glucose_logs ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users manage own glucose logs"
  ON zane_glucose_logs FOR ALL TO public
  USING (((select auth.uid()) = user_id)) WITH CHECK (((select auth.uid()) = user_id));
CREATE POLICY "coaches read client glucose logs"
  ON zane_glucose_logs FOR SELECT TO public
  USING (EXISTS ( SELECT 1 FROM zane_coaching zc
    WHERE zc.client_id = zane_glucose_logs.user_id
      AND zc.coach_id = (select auth.uid()) AND zc.coach_id <> zc.client_id AND zc.status = 'active'));

-- ── Support tickets (migrations 0085/0086 + archive_support_tickets) ────────────
-- A support ticket is a zane_coaching row with id LIKE 'support_%' between the
-- user (client_id) and the admin (coach_id), carrying support_status/category.
-- Reuses the coaching chat + realtime infra so no new client code is needed.

CREATE OR REPLACE FUNCTION public.open_support_chat(p_category text DEFAULT 'question'::text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_admin_id uuid;
  v_user_id  uuid;
  v_id       text;
BEGIN
  v_user_id := auth.uid();
  SELECT id INTO v_admin_id FROM auth.users WHERE email = 'office@btc-prime.biz' LIMIT 1;
  IF v_admin_id IS NULL THEN RAISE EXCEPTION 'Support unavailable'; END IF;
  IF v_user_id = v_admin_id THEN RAISE EXCEPTION 'Admin cannot open support chat'; END IF;
  IF p_category NOT IN ('feature_request', 'bug', 'question') THEN p_category := 'question'; END IF;
  v_id := 'support_' || gen_random_uuid()::text;
  INSERT INTO zane_coaching (id, coach_id, client_id, status, support_status, support_category)
  VALUES (v_id, v_admin_id, v_user_id, 'active', 'open', p_category);
  RETURN v_id;
END;
$function$;

REVOKE EXECUTE ON FUNCTION public.open_support_chat(text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.open_support_chat(text) TO authenticated;

CREATE OR REPLACE FUNCTION public.set_support_status(p_coaching_id text, p_status text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_admin_id uuid;
BEGIN
  SELECT id INTO v_admin_id FROM auth.users WHERE email = 'office@btc-prime.biz' LIMIT 1;
  IF auth.uid() <> v_admin_id THEN RAISE EXCEPTION 'Unauthorized'; END IF;
  IF p_status NOT IN ('open', 'in_progress', 'resolved') THEN RAISE EXCEPTION 'Invalid status'; END IF;
  UPDATE zane_coaching SET support_status = p_status
  WHERE id = p_coaching_id AND id LIKE 'support_%';
END;
$function$;

REVOKE EXECUTE ON FUNCTION public.set_support_status(text, text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.set_support_status(text, text) TO authenticated;

CREATE OR REPLACE FUNCTION public.archive_support_ticket(p_coaching_id text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_admin_id uuid;
BEGIN
  SELECT id INTO v_admin_id FROM auth.users WHERE email = 'office@btc-prime.biz' LIMIT 1;
  IF auth.uid() <> v_admin_id THEN RAISE EXCEPTION 'Unauthorized'; END IF;
  UPDATE zane_coaching SET archived = true, archived_at = now()
  WHERE id = p_coaching_id AND id LIKE 'support_%';
END;
$function$;

REVOKE EXECUTE ON FUNCTION public.archive_support_ticket(text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.archive_support_ticket(text) TO authenticated;

CREATE OR REPLACE FUNCTION public.delete_support_ticket(p_coaching_id text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_admin_id uuid;
BEGIN
  SELECT id INTO v_admin_id FROM auth.users WHERE email = 'office@btc-prime.biz' LIMIT 1;
  IF auth.uid() <> v_admin_id THEN RAISE EXCEPTION 'Unauthorized'; END IF;
  IF p_coaching_id NOT LIKE 'support_%' THEN RAISE EXCEPTION 'Not a support ticket'; END IF;
  DELETE FROM zane_coaching_notes   WHERE coaching_id = p_coaching_id;
  DELETE FROM zane_coaching_threads WHERE coaching_id = p_coaching_id;
  DELETE FROM zane_coaching          WHERE id          = p_coaching_id;
END;
$function$;

REVOKE EXECUTE ON FUNCTION public.delete_support_ticket(text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.delete_support_ticket(text) TO authenticated;

CREATE OR REPLACE FUNCTION public.get_archived_support_chats()
 RETURNS TABLE(coaching_id text, client_id uuid, client_name text, client_email text, support_status text, support_category text, last_message_at timestamp with time zone, last_message_body text, unread_count bigint)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_admin_id uuid;
BEGIN
  SELECT id INTO v_admin_id FROM auth.users WHERE email = 'office@btc-prime.biz' LIMIT 1;
  IF auth.uid() <> v_admin_id THEN RAISE EXCEPTION 'Unauthorized'; END IF;
  RETURN QUERY
  SELECT
    c.id,
    c.client_id,
    COALESCE(p.name, u.email)::text,
    u.email::text,
    c.support_status,
    c.support_category,
    (SELECT MAX(n.created_at) FROM zane_coaching_notes n WHERE n.coaching_id = c.id),
    (SELECT n.body          FROM zane_coaching_notes n WHERE n.coaching_id = c.id ORDER BY n.created_at DESC LIMIT 1),
    (SELECT COUNT(*)        FROM zane_coaching_notes n WHERE n.coaching_id = c.id AND n.author_id <> v_admin_id AND n.read_at IS NULL)
  FROM zane_coaching c
  JOIN auth.users u ON u.id = c.client_id
  LEFT JOIN zane_profiles p ON p.id = c.client_id
  WHERE c.id LIKE 'support_%'
    AND COALESCE(c.archived, false)
  ORDER BY (SELECT MAX(n.created_at) FROM zane_coaching_notes n WHERE n.coaching_id = c.id) DESC NULLS LAST;
END;
$function$;

REVOKE EXECUTE ON FUNCTION public.get_archived_support_chats() FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.get_archived_support_chats() TO authenticated;

CREATE OR REPLACE FUNCTION public.get_user_support_chats()
 RETURNS TABLE(coaching_id text, support_status text, support_category text, created_at timestamp with time zone, last_message_at timestamp with time zone, last_message_body text, unread_count bigint, archived boolean, archived_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    c.id,
    c.support_status,
    c.support_category,
    c.created_at,
    (SELECT MAX(n.created_at) FROM zane_coaching_notes n WHERE n.coaching_id = c.id),
    (SELECT n.body          FROM zane_coaching_notes n WHERE n.coaching_id = c.id ORDER BY n.created_at DESC LIMIT 1),
    (SELECT COUNT(*)        FROM zane_coaching_notes n WHERE n.coaching_id = c.id AND n.author_id <> auth.uid() AND n.read_at IS NULL),
    COALESCE(c.archived, false),
    c.archived_at
  FROM zane_coaching c
  WHERE c.client_id = auth.uid()
    AND c.id LIKE 'support_%'
  ORDER BY COALESCE(
    (SELECT MAX(n.created_at) FROM zane_coaching_notes n WHERE n.coaching_id = c.id),
    c.created_at
  ) DESC;
END;
$function$;

REVOKE EXECUTE ON FUNCTION public.get_user_support_chats() FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.get_user_support_chats() TO authenticated;

-- ── VIP backgrounds (migration 0103) ────────────────────────────────────────────
-- Admin-granted decorative background (zane_user_settings.vip_background).

CREATE OR REPLACE FUNCTION public.get_user_vip_backgrounds()
 RETURNS TABLE(email text, bg_key text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RETURN;
  END IF;
  RETURN QUERY
  SELECT u.email::text, us.vip_background::text
  FROM zane_user_settings us
  JOIN auth.users u ON u.id = us.user_id
  WHERE us.vip_background IS NOT NULL
  ORDER BY u.email;
END;
$function$;

REVOKE EXECUTE ON FUNCTION public.get_user_vip_backgrounds() FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.get_user_vip_backgrounds() TO authenticated;

CREATE OR REPLACE FUNCTION public.set_user_vip_background(p_email text, p_bg_key text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id uuid;
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;
  SELECT id INTO v_user_id FROM auth.users WHERE lower(email) = lower(trim(p_email)) LIMIT 1;
  IF v_user_id IS NULL THEN
    RETURN 'ERROR:not_found';
  END IF;
  INSERT INTO zane_user_settings (user_id, vip_background)
  VALUES (v_user_id, NULLIF(trim(p_bg_key), ''))
  ON CONFLICT (user_id) DO UPDATE SET vip_background = NULLIF(trim(p_bg_key), '');
  RETURN 'ok';
END;
$function$;

REVOKE EXECUTE ON FUNCTION public.set_user_vip_background(text, text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.set_user_vip_background(text, text) TO authenticated;

-- Legacy onboarded-users admin lookup (only users who have ≥1 plan). Superseded
-- by get_all_users_admin (covers every account) but kept for backward compat.
CREATE OR REPLACE FUNCTION public.get_users_with_plans()
 RETURNS TABLE(user_id uuid, name text, email text, joined_at timestamp with time zone, approved boolean, plan_count integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.email() IS DISTINCT FROM 'office@btc-prime.biz' THEN
    RETURN;
  END IF;
  RETURN QUERY
    SELECT p.id, p.name, u.email::text, u.created_at, p.approved,
           COUNT(s.id)::int AS plan_count
    FROM zane_profiles p
    JOIN auth.users u ON u.id = p.id
    JOIN zane_schedules s ON s.user_id = p.id
    GROUP BY p.id, p.name, u.email, u.created_at, p.approved
    ORDER BY u.created_at DESC;
END;
$function$;

REVOKE EXECUTE ON FUNCTION public.get_users_with_plans() FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.get_users_with_plans() TO authenticated;
